 48	#define MAX_COMMAND 4096
 49	
 50	static int command_pipe_read;
 51	static int command_pipe_write;
 52	static int result_pipe_read;
 53	static int result_pipe_write;
 54	
 55	static pthread_mutex_t lock = PTHREAD_MUTEX_INITIALIZER;
 56	
 57	static int module_initialized = 0;
 58	
 59	/********************************************************************/
 60	/* util functions                                                   */
 61	/********************************************************************/
 62	
 63	static void lock_system(void) {
 64	  if (pthread_mutex_lock(&lock) != 0) {
 65	    printf("pthread_mutex_lock fails\n");
 66	    abort();
 67	  }
 68	}
 69	
 70	static void unlock_system(void) {
 71	  if (pthread_mutex_unlock(&lock) != 0) {
 72	    printf("pthread_mutex_unlock fails\n");
 73	    abort();
 74	  }
 75	}
