 77	static void write_pipe(int p, char *b, int size) {
 78	  while (size) {
 79	    int ret = write(p, b, size);
 80	
 81	    if (ret <= 0) exit(0);
 82	
 83	    b += ret;
 84	    size -= ret;
 85	  }
 86	}
 87	
 88	static void read_pipe(int p, char *b, int size) {
 89	  while (size) {
 90	    int ret = read(p, b, size);
 91	
 92	    if (ret <= 0) exit(0);
 93	
 94	    b += ret;
 95	    size -= ret;
 96	  }
 97	}
