110	/********************************************************************/
111	/* background process                                               */
112	/********************************************************************/
113	
114	/* This function is run by background process. It waits for a command,
115	 * runs it, and reports status back. It exits (in normal situations)
116	 * when the main process exits, because then a "read" on the pipe
117	 * will return 0, in which case "read_pipe" exits.
118	 */
119	static void background_system_process(void) {
120	  int len;
121	  int ret;
122	  char command[MAX_COMMAND+1];
123	
124	  while (1) {
125	    read_pipe(command_pipe_read, (char *)&len, sizeof(int));
126	    read_pipe(command_pipe_read, command, len);
127	    ret = system(command);
128	    write_pipe(result_pipe_write, (char *)&ret, sizeof(int));
129	  }
130	}
131	
132	/********************************************************************/
133	/* background_system()                                              */
134	/*     return -1 on error, 0 on success                             */
135	/********************************************************************/
136	
137	int background_system(char *command) {
138	  int res;
139	  int len;
140	
141	  if (module_initialized == 0) {
142	    printf("FATAL: calling 'background_system' but 'start_background_system' was not called\n");
143	    abort();
144	  }
145	
146	  len = strlen(command)+1;
147	
148	  if (len > MAX_COMMAND) {
149	    printf("FATAL: command too long. Increase MAX_COMMAND (%d).\n", MAX_COMMAND);
150	    printf("command was: '%s'\n", command);
151	    abort();
152	  }
153	
154	  /* only one command can run at a time, so let's lock/unlock */
155	  lock_system();
156	  write_pipe(command_pipe_write, (char *)&len, sizeof(int));
157	  write_pipe(command_pipe_write, command, len);
158	  read_pipe(result_pipe_read, (char *)&res, sizeof(int));
159	  unlock_system();
160	
161	  if (res == -1 || !WIFEXITED(res) || WEXITSTATUS(res) != 0) return -1;
162	
163	  return 0;
164	}
165	
166	/********************************************************************/
167	/* start_background_system()                                        */
168	/*     initializes the "background system" module                   */
169	/*     to be called very early by the main processing               */
170	/********************************************************************/
171	
172	void start_background_system(void) {
173	  int p[2];
174	  pid_t son;
175	
176	  if (module_initialized == 1)
177	    return;
178	
179	  module_initialized = 1;
180	
181	  if (pipe(p) == -1) {
182	    perror("pipe");
183	    exit(1);
184	  }
185	
186	  command_pipe_read  = p[0];
187	  command_pipe_write = p[1];
188	
189	  if (pipe(p) == -1) {
190	    perror("pipe");
191	    exit(1);
192	  }
193	
194	  result_pipe_read  = p[0];
195	  result_pipe_write = p[1];
196	  son = fork();
197	
198	  if (son == -1) {
199	    perror("fork");
200	    exit(1);

    exit(1);
  }

  if (son) {
    close(result_pipe_write);
    close(command_pipe_read);
    return;
  }

  close(result_pipe_read);
  close(command_pipe_write);
  background_system_process();
}

int rt_sleep_ns (uint64_t x)
{
  struct timespec myTime;
  clock_gettime(CLOCK_MONOTONIC, &myTime);
  myTime.tv_sec += x/1000000000ULL;
  myTime.tv_nsec = x%1000000000ULL;
  if (myTime.tv_nsec>=1000000000) {
    myTime.tv_nsec -= 1000000000;
    myTime.tv_sec++;
  }

  return clock_nanosleep(CLOCK_MONOTONIC, TIMER_ABSTIME, &myTime, NULL);
}

